before_code:
module counter_16bit (
  input clk,
  input reset_n,
  output reg [15:0] count
);

  always @(posedge clk)
  begin
    if (!reset_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule

after_code:
module counter_16bit (
  input clk,
  input reset_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge reset_n)
  begin
    if (!reset_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule
